INSERT INTO `creature_text` (`entry`, `text_group`, `id`, `text`, `text_female`, `text_range`, `type`, `language`, `probability`, `emote`, `duration`, `sound`, `comment`) VALUES
(22963, 0, 0, "Gakarah ma!", "", 0, 12, 0, 100, 0, 0, 0, "Bonechewer Worker"),
(22963, 0, 1, "Lok narash!", "", 0, 12, 0, 100, 0, 0, 0, "Bonechewer Worker"),
(22963, 0, 2, "Lok'tar Illadari!", "", 0, 12, 0, 100, 0, 0, 0, "Bonechewer Worker"),
(22963, 0, 3, "The blood is our power!", "", 0, 12, 0, 100, 0, 0, 0, "Bonechewer Worker"),
(23028, 0, 0, "I've seen female Gnomes hit harder than you!", "", 0, 14, 0, 100, 0, 0, 0, "Bonechewer Taskmaster"),
(23028, 0, 1, "If you don't start throwing some real punches, you'll be cleaning the drake stalls for a year!", "", 0, 14, 0, 100, 0, 0, 0, "Bonechewer Taskmaster"),
(23028, 0, 2, "Stop your slacking and fight like a true fel orc!", "", 0, 14, 0, 100, 0, 0, 0, "Bonechewer Taskmaster"),
(23028, 0, 3, "You call that an offense? I've seen more offensive tallstriders!", "", 0, 14, 0, 100, 0, 0, 0, "Bonechewer Taskmaster"),
(23028, 1, 0, "%s becomes increasingly enraged as he sees his allies fall in battle!", "", 0, 16, 0, 100, 0, 0, 0, "Bonechewer Taskmaster");
